INSERT INTO prize_orders (order_id, prize_name_raw, supplier_id, order_source, source_file, order_date, case_count, pieces_per_case, unit_cost, case_cost, total_tax_included, destination, status, notes, import_meta, unplanned_flag)
SELECT gen_random_uuid(), csv.nm, 'SGP', 'csv_migration', 'prize_orders_all.csv', csv.odate::date, csv.qty::numeric, csv.pieces::numeric, csv.ucost::numeric, csv.ccost::numeric, csv.tincl::numeric, csv.dest, csv.st, csv.nt, jsonb_build_object('cart_id', csv.cart, 'product_code', csv.pcode, 'migration_date', '2026-05-27'), false
FROM csv WHERE NOT EXISTS (SELECT 1 FROM prize_orders po WHERE po.supplier_id='SGP' AND po.order_date=csv.odate::date AND po.prize_name_raw=csv.nm AND po.case_count=csv.qty::numeric);
